// @ts-nocheck
const API_BASE_URL=import.meta.env.VITE_API_URL||"http://localhost:3000/api";class ApiService{async request(e,t={}){const r=`${API_BASE_URL}${e}`,s={...t,credentials:"include",headers:{"Content-Type":"application/json",...t.headers}};try{const e=await fetch(r,s),t=await e.json();if(!e.ok)throw new Error(t.error||"Request failed");return t}catch(e){throw console.error("API request failed:",e),e}}async login(e,t){return this.request("/auth/login",{method:"POST",body:JSON.stringify({email:e,password:t})})}async register(e,t,r){return this.request("/auth/register",{method:"POST",body:JSON.stringify({email:e,password:t,name:r})})}async logout(){return this.request("/auth/logout",{method:"POST"})}async getMe(){return this.request("/auth/me")}async getRecords(e={}){const t=new URLSearchParams(e).toString(),r="/records"+(t?`?${t}`:"");return this.request(r)}async getRecordsMeta(){return this.request("/records/meta")}getGoogleAuthUrl(){return`${API_BASE_URL}/auth/google`}async getAnalyticsSummary(){return this.request("/analytics/summary")}async getChartData(e,t="30d"){return this.request(`/analytics/charts/${e}?period=${t}`)}async getRealtimeStats(){return this.request("/analytics/realtime")}async forgotPassword(e){return this.request("/auth/forgot-password",{method:"POST",body:JSON.stringify({email:e})})}async resetPassword(e,t){return this.request("/auth/reset-password",{method:"POST",body:JSON.stringify({token:e,newPassword:t})})}async validateResetToken(e){return this.request(`/auth/validate-reset-token/${e}`)}async changePassword(e,t){return this.request("/auth/change-password",{method:"POST",body:JSON.stringify({currentPassword:e,newPassword:t})})}}export default new ApiService;